import osimport shutilfrom PIL import Imagefrom typing import Dict, Tupledef sort_png_by_size(folder_path: str) -> None:    """    将指定文件夹中的PNG图片按尺寸分类到子文件夹，并统计各尺寸数量    Args:        folder_path: 包含PNG图片的文件夹路径    """    # 检查输入路径是否存在    if not os.path.isdir(folder_path):        print(f"错误：文件夹路径 '{folder_path}' 不存在")        return    # 初始化尺寸统计字典    size_count: Dict[Tuple[int, int], int] = {}    # 记录移动失败的文件    failed_files: list[str] = []    print(f"开始扫描文件夹: {folder_path}")    print("-" * 50)    # 遍历文件夹中的所有文件    for filename in os.listdir(folder_path):        # 只处理PNG文件        if filename.lower().endswith(".png"):            file_path = os.path.join(folder_path, filename)            # 跳过子文件夹            if os.path.isdir(file_path):                continue            try:                # 打开图片获取尺寸                with Image.open(file_path) as img:                    width, height = img.size                # 更新统计                size_key = (height, width)                size_count[size_key] = size_count.get(size_key, 0) + 1                # 创建目标文件夹                target_folder_name = f"size_h{height}w{width}"                target_folder_path = os.path.join(folder_path, target_folder_name)                if not os.path.exists(target_folder_path):                    os.makedirs(target_folder_path)                    print(f"创建文件夹: {target_folder_name}")                # 移动文件                target_file_path = os.path.join(target_folder_path, filename)                # 处理重名文件                counter = 1                while os.path.exists(target_file_path):                    name, ext = os.path.splitext(filename)                    target_file_path = os.path.join(target_folder_path, f"{name}_{counter}{ext}")                    counter += 1                shutil.move(file_path, target_file_path)            except Exception as e:                failed_files.append(f"{filename}: {str(e)}")                continue    # 输出统计结果    print("\n" + "=" * 50)    print("图片尺寸统计结果:")    print("=" * 50)    if not size_count:        print("未找到任何PNG图片")        return    # 按数量从多到少排序    sorted_sizes = sorted(size_count.items(), key=lambda x: x[1], reverse=True)    total_files = sum(size_count.values())    for (height, width), count in sorted_sizes:        percentage = (count / total_files) * 100        print(f"尺寸: {height}x{width} | 数量: {count} | 占比: {percentage:.1f}%")    print("-" * 50)    print(f"总计处理: {total_files} 个PNG文件")    if failed_files:        print(f"\n处理失败的文件 ({len(failed_files)}个):")        for file in failed_files:            print(f"  - {file}")    else:        print("\n所有文件处理成功!")if __name__ == "__main__":    # 请将下面的路径替换为你的图片文件夹路径    # 示例: r"C:\Users\YourName\Pictures\png_files"    # 或者使用相对路径: "./png_images"    IMAGE_FOLDER_PATH = r"E:\project\Dataset\Key_slices\Key_slices"  # 默认使用当前脚本所在文件夹    sort_png_by_size(IMAGE_FOLDER_PATH)    # 保持窗口打开（Windows双击运行时）    input("\n按回车键退出...")